/**
 * Record builder and I/O utilities.
 *
 * Standardizes the JSON record format used across all scripts.
 */

import { readFile, writeFile } from 'node:fs/promises';
import { join } from 'node:path';

/**
 * Build a base provenance record (generated by txt2img scripts).
 */
export function buildBaseRecord(id, assetPath, imageData, provenance) {
  return {
    id,
    schema_version: '2.0.0',
    created_at: new Date().toISOString(),
    asset_path: assetPath,
    image: {
      format: 'png',
      width: imageData.width || 1024,
      height: imageData.height || 1024,
      bytes: imageData.bytes || 0,
    },
    provenance,
    judgment: null,
    canon: null,
    iteration: null,
  };
}

/**
 * Build an identity record (extends base with identity + lineage blocks).
 */
export function buildIdentityRecord(baseRecord, identity, lineage) {
  return {
    ...baseRecord,
    identity,
    lineage,
  };
}

/**
 * Load a record by asset ID from a records directory.
 * @param {string} recordsDir — absolute path to records/
 * @param {string} assetId — record filename (without .json)
 * @returns {Promise<Object|null>}
 */
export async function loadRecord(recordsDir, assetId) {
  const path = join(recordsDir, `${assetId}.json`);
  try {
    const raw = await readFile(path, 'utf-8');
    return JSON.parse(raw);
  } catch (err) {
    if (err.code === 'ENOENT') return null;
    throw new Error(`Failed to load record ${assetId}: ${err.message}`);
  }
}

/**
 * Save a record to disk.
 * @param {string} recordsDir — absolute path to records/
 * @param {string} assetId — record filename (without .json)
 * @param {Object} record — the record object
 */
export async function saveRecord(recordsDir, assetId, record) {
  const path = join(recordsDir, `${assetId}.json`);
  await writeFile(path, JSON.stringify(record, null, 2) + '\n');
}
